<!DOCTYPE html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Station Weather · Track Rail</title><link rel="preconnect" href="https://fonts.bunny.net"><link href="https://fonts.bunny.net/css?family=figtree:400,500,600,700,800&display=swap" rel="stylesheet"><style>
*{box-sizing:border-box}body{margin:0;background:#f1f5f9;color:#0f172a;font-family:Figtree,system-ui,sans-serif}.weather-nav{height:72px;background:#fff;border-bottom:1px solid #e2e8f0;display:flex;align-items:center;justify-content:space-between;padding:0 max(24px,calc((100% - 1180px)/2));gap:20px}.brand{color:#312e81;font-size:20px;font-weight:800;text-decoration:none}.nav-actions{display:flex;align-items:center;gap:14px}.nav-actions a{color:#475569;font-size:14px;font-weight:700;text-decoration:none}.nav-btn{border-radius:10px;background:#4f46e5;color:#fff!important;padding:10px 15px}.weather-main{max-width:1180px;margin:auto;padding:48px 24px}.hero{display:flex;align-items:flex-end;justify-content:space-between;gap:30px;color:#fff;border-radius:26px;padding:42px;background:linear-gradient(120deg,#1e1b4b,#4338ca 58%,#0ea5e9);box-shadow:0 18px 35px #312e8140}.hero h1{font-size:42px;line-height:1.08;margin:10px 0 12px}.hero p{max-width:580px;color:#dbeafe;font-size:16px;line-height:1.6;margin:0}.role-badge{border:1px solid #ffffff55;border-radius:999px;padding:9px 14px;color:#e0e7ff;font-size:12px;font-weight:800;text-transform:uppercase;letter-spacing:.08em;white-space:nowrap}.panel{background:#fff;border:1px solid #dbe3ef;border-radius:20px;box-shadow:0 8px 25px #0f172a0d;padding:24px;margin-top:22px}.panel h2{font-size:20px;margin:0 0 5px}.muted{color:#64748b;font-size:14px}.station-row{display:flex;gap:12px;margin-top:18px}.station-row select,.city-input{flex:1;border:1px solid #cbd5e1;border-radius:11px;background:#f8fafc;padding:13px 14px;color:#0f172a;font-size:14px;outline:none}.station-row select:focus,.city-input:focus{border-color:#4f46e5;box-shadow:0 0 0 3px #c7d2fe}.primary-btn{border:0;border-radius:11px;background:#4f46e5;color:#fff;padding:13px 20px;font-size:14px;font-weight:800;cursor:pointer}.primary-btn:hover{background:#3730a3}.assigned{display:inline-block;margin-top:12px;color:#4f46e5;font-size:13px;font-weight:700;cursor:pointer}.state{display:none;border-radius:16px;margin-top:22px;padding:22px}.loading{background:#eef2ff;color:#3730a3}.error{background:#fef2f2;border:1px solid #fecaca;color:#b91c1c}.weather-card{display:none;overflow:hidden;margin-top:22px;border:1px solid #dbe3ef;border-radius:22px;background:#fff;box-shadow:0 15px 30px #0f172a12}.weather-top{display:flex;align-items:center;justify-content:space-between;gap:20px;padding:28px;background:linear-gradient(120deg,#4f46e5,#0284c7);color:#fff}.weather-top h2{font-size:28px;margin:0}.weather-top p{color:#dbeafe;margin:7px 0 0}.weather-icon{font-size:64px}.weather-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;padding:24px}.stat{border-radius:14px;background:#f8fafc;padding:17px;text-align:center}.stat label{color:#64748b;display:block;font-size:11px;font-weight:800;letter-spacing:.08em;text-transform:uppercase}.stat strong{display:block;color:#0f172a;font-size:27px;margin-top:6px}.weather-foot{display:flex;justify-content:space-between;gap:20px;border-top:1px solid #e2e8f0;padding:18px 24px;color:#475569;font-size:14px}.city-form{display:flex;gap:12px;margin-top:18px}.links{display:flex;flex-wrap:wrap;gap:12px;margin-top:24px}.links a{border:1px solid #cbd5e1;border-radius:11px;background:#fff;color:#334155;padding:11px 15px;text-decoration:none;font-size:13px;font-weight:700}.links a:hover{border-color:#818cf8;color:#4338ca}@media(max-width:700px){.weather-nav{padding:0 16px}.brand{font-size:17px}.nav-actions a:not(.nav-btn){display:none}.weather-main{padding:24px 16px}.hero{display:block;padding:28px}.hero h1{font-size:32px}.role-badge{display:inline-block;margin-top:25px}.station-row,.city-form{display:block}.station-row select,.city-input{display:block;width:100%;margin-bottom:10px}.primary-btn{width:100%}.weather-stats{grid-template-columns:repeat(2,1fr)}.weather-top{padding:22px}.weather-icon{font-size:45px}.weather-foot{display:block}.weather-foot span{display:block;margin-top:6px}}
</style></head><body>
<nav class="weather-nav"><a class="brand" href="{{ url('/') }}">Track Rail</a><div class="nav-actions"><a href="{{ route('weather.index') }}">Weather</a>@auth<a href="{{ Auth::user()->isAdmin() ? route('admin.dashboard') : (Auth::user()->isStationMaster() ? route('station-master.dashboard') : route('dashboard')) }}" class="nav-btn">Dashboard</a>@else<a href="{{ route('login') }}">Log in</a><a href="{{ route('register') }}" class="nav-btn">Register</a>@endauth</div></nav>
<main class="weather-main"><section class="hero"><div><span class="role-badge">{{ ucfirst(str_replace('_', ' ', $userType)) }} access</span><h1>Weather for your journey</h1><p>Check current conditions at any station before you travel. Weather data is refreshed every 30 minutes.</p></div></section>
<section class="panel"><h2>Check a station</h2><p class="muted">Select a railway station to load its current weather.</p><div class="station-row"><select id="stationSelect"><option value="">Choose a station</option>@foreach($stations as $station)<option value="{{ $station->id }}">{{ $station->railOrder() }}. {{ $station->name }} ({{ $station->code }})</option>@endforeach</select><button class="primary-btn" id="stationButton" type="button">Check weather</button></div>@auth @if($userType === 'station_master' && Auth::user()->station_id)<button class="assigned" type="button" onclick="quickSelectStation({{ Auth::user()->station_id }})">Use my assigned station</button>@endif @endauth</section>
<div id="loadingState" class="state loading">Loading current weather…</div><div id="errorState" class="state error"><strong>Unable to load weather</strong><div id="errorMessage"></div></div>
<section id="weatherResult" class="weather-card"><div class="weather-top"><div><h2 id="weatherCity"></h2><p id="weatherCountry"></p></div><div id="weatherIcon" class="weather-icon"></div></div><div class="weather-stats"><div class="stat"><label>Temperature</label><strong><span id="weatherTemp"></span>°C</strong></div><div class="stat"><label>Feels like</label><strong><span id="weatherFeels"></span>°C</strong></div><div class="stat"><label>Humidity</label><strong><span id="weatherHumidity"></span>%</strong></div><div class="stat"><label>Wind</label><strong><span id="weatherWind"></span> km/h</strong></div></div><div class="weather-foot"><span><span id="weatherDescIcon"></span> <strong id="weatherDescription"></strong></span><span>Pressure: <strong id="weatherPressure"></strong> · <span id="weatherCached"></span></span></div></section>
<section class="panel"><h2>Search any city</h2><p class="muted">Look up weather anywhere in the world.</p><form id="customSearchForm" class="city-form"><input id="customCity" class="city-input" required minlength="2" placeholder="e.g. Dhaka, London, Tokyo"><button class="primary-btn" type="submit">Search city</button></form><div id="customResult"></div></section>
<div class="links">@if($userType === 'passenger')<a href="{{ route('dashboard') }}">My bookings</a><a href="{{ route('dashboard') }}">Search trains</a>@elseif($userType === 'station_master')<a href="{{ route('station-master.dashboard') }}">Station dashboard</a>@elseif($userType === 'admin')<a href="{{ route('admin.dashboard') }}">Admin panel</a>@else<a href="{{ route('login') }}">Log in to book tickets</a><a href="{{ route('register') }}">Create an account</a>@endif</div></main>
<script>
const $=id=>document.getElementById(id), select=$('stationSelect');function showState(id,show){$(id).style.display=show?'block':'none'}function renderWeather(w){$('weatherCity').textContent=w.city;$('weatherCountry').textContent=w.country;$('weatherIcon').textContent=w.icon;$('weatherTemp').textContent=w.temperature;$('weatherFeels').textContent=w.feels_like;$('weatherHumidity').textContent=w.humidity;$('weatherWind').textContent=w.wind_speed;$('weatherPressure').textContent=w.pressure+' hPa';$('weatherDescription').textContent=w.description;$('weatherDescIcon').textContent=w.icon;$('weatherCached').textContent=w.cached?'Cached':'Live';$('weatherResult').style.display='block'}async function loadWeather(url){showState('errorState',false);showState('loadingState',true);$('weatherResult').style.display='none';try{const response=await fetch(url,{headers:{Accept:'application/json'}});const data=await response.json();if(!response.ok||!data.success)throw new Error(data.message||'Weather service unavailable');renderWeather(data.weather)}catch(e){$('errorMessage').textContent=e.message;showState('errorState',true)}finally{showState('loadingState',false)}}$('stationButton').addEventListener('click',()=>{if(select.value)loadWeather('{{ url('/weather/station') }}/'+select.value)});function quickSelectStation(id){select.value=id;loadWeather('{{ url('/weather/station') }}/'+id)}$('customSearchForm').addEventListener('submit',e=>{e.preventDefault();loadWeather('{{ route('weather.search') }}?city='+encodeURIComponent($('customCity').value))});
</script></body></html>
